CREATE PROCEDURE Example_http_st_dxf_entity ()
{
  DECLARE ses, ctx ANY;
  ses := string_output();
  FOR (SELECT a1, DESERIALIZE(geometry) AS geom FROM Demo.Demo.Example_Countries) DO
    http_st_dxf_entity(geom, vector(62, 0), ses);
  STRING_TO_FILE('examples/Example_http_st_dxf_entity.dxf', ses, -2);
};

CREATE PROCEDURE Another_http_st_dxf_entity ()
{
  DECLARE ses, ctx ANY;
  ses := string_output();
  FOR (SELECT a1, DESERIALIZE(poly) AS geom FROM Demo.Demo.Example_Polygons WHERE id = 1) DO
    http_st_dxf_entity(geom, vector(62, 0), ses);
  STRING_TO_FILE('examples/Another_http_st_dxf_entity.dxf', ses, -2);
};

CREATE PROCEDURE Complex_http_st_dxf_entity ()
{
  DECLARE ses, ctx ANY;
  ses := string_output();
  FOR (SELECT c.id, c.name, p.poly FROM Demo.Demo.Example_Countries AS c JOIN Demo.Demo.Example_Polygons AS p ON c.id = p.id) DO
    http_st_dxf_entity(p.poly, vector(62, 0), ses);
  STRING_TO_FILE('examples/Complex_http_st_dxf_entity.dxf', ses, -2);
};

